package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
)

func main() {
	resp, err := http.Get("https://api.example.com/data")
	if err != nil {
		fmt.Println("Error fetching data:", err)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading body:", err)
		return
	}

	fmt.Println("Request Content:")
	fmt.Println(string(body))
}
```

This code fetches data from a specified URL, reads the response body, and prints it out. The `io/ioutil` package is used for simplifying I/O operations, and `net/http` handles the HTTP requests. Go's simplicity and efficiency make it a great choice for this kind of task!

